  calc_approvals_sequence_position_from_workflow_steps(t.approval_id) AS sequence_position_from_workflow_steps,
  calc_approvals_requires_human_approval_from_workflow_steps(t.approval_id) AS requires_human_approval_from_workflow_steps
FROM approvals t;

