  t.filled_by_automated_pipeline,
  t.owned_by,
  t.delegates_to,
  calc_roles_workflow_steps(t.role_id) AS workflow_steps,
  t.from_delegates_to,
  calc_roles_all_linked_workflow_steps(t.role_id) AS all_linked_workflow_steps,
  calc_roles_distinct_workflows_for_linked_steps(t.role_id) AS distinct_workflows_for_linked_steps,
  t.workflow_artifacts
FROM roles t;

